		"rationale":                triage.Rationale,
		"suggested_amendments":     amendments,
		"suggested_followup_beads": followups,
		"status":                   report.Status,
		"detail":                   report.Detail,
		"base_rev":                 report.BaseRev,
		"result_rev":               report.ResultRev,
