		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:      parking.Event.Kind,
			Summary:   parking.Event.Summary,
			Body:      parking.Event.Body,
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
	}
	if !parking.RetryAfter.IsZero() {
		if err := w.Store.SetExecutionCooldown(candidate.ID, parking.RetryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
				return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
			})
			if ctx.Err() != nil {
				return result, ctx.Err()
			}
			continue
		}
		report.RetryAfter = parking.RetryAfter.Format(time.RFC3339)
	}
}

					_, _ = fmt.Fprintf(runtime.Log, "route-exclusion update failed for %s: %v (continuing)\n", candidate.ID, err)
				}
			}
			emitRouteFailureEvent(w.Store, candidate.ID, assignee, report, now().UTC())
			// Route exclusion (TTL-based via RouteExclusionWindow) is the
			// correct mechanism — no per-bead cooldown. Bead is immediately
			// reclaimable; next attempt routes around the failed (provider,model).
		} else if isNoViableProviderReport(report) {
			report.OutcomeReason = FailureModeNoViableProvider
			report.Disrupted = true
			report.DisruptionReason = "no_viable_provider"
			// Transition the worker to paused-infra: leave every bead
			// immediately reclaimable, pause this worker for PausedInfraInterval,
			// then re-evaluate the full queue (P6 + ADR-024 §Infra Fallback).
			pausedInfraUntil = now().UTC().Add(PausedInfraInterval)
		} else {
			report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
			if shouldSuppressNoProgress(report) {
				retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
				if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
						return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
					})
					if ctx.Err() != nil {
						return result, ctx.Err()
					}
					continue
				}
				report.RetryAfter = retryAfter.Format(time.RFC3339)
			}
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	}
}

	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) {
		return exitErr.ExitCode()
	}
	return -1
}

func assertAllTrySubprocessesFinished(t *testing.T, results []trySubprocessResult, wantExitCode int) {
	t.Helper()

	for i, res := range results {
		require.NoErrorf(t, res.err, "subprocess %d (%s) failed unexpectedly: %s", i, res.beadID, res.output)
		assert.Equalf(t, wantExitCode, res.exitCode, "subprocess %d (%s) exit code mismatch: %s", i, res.beadID, res.output)
		assert.Containsf(t, res.output, "status: success", "subprocess %d (%s) must report a success status", i, res.beadID)
		assert.Containsf(t, res.output, "result_rev:", "subprocess %d (%s) must report a result revision", i, res.beadID)
	}
}

func assertTryClaimLossOutput(t *testing.T, res trySubprocessResult) {
	t.Helper()

	assert.NotNil(t, res.err, "losing subprocess must exit non-zero")
	assert.NotEqual(t, 0, res.exitCode, "losing subprocess must not exit zero")
	lower := strings.ToLower(res.output)
	if strings.Contains(lower, "bead is not execution-ready") ||
		strings.Contains(lower, "bead is not claimable") ||
		strings.Contains(lower, "cannot claim") ||
		strings.Contains(lower, "already claimed") {
		return
	}
	t.Fatalf("losing subprocess output did not follow the not-claimable path:\n%s", res.output)
}

func completeExecutionBundles(t *testing.T, projectRoot string) []string {
	t.Helper()

	execDir := ddxroot.JoinProject(projectRoot, "executions")
	entries, err := os.ReadDir(execDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		t.Fatalf("read execution dir %s: %v", execDir, err)
	}
	var bundles []string
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dir := filepath.Join(execDir, entry.Name())
		if fileExists(filepath.Join(dir, "manifest.json")) &&
			fileExists(filepath.Join(dir, "prompt.md")) &&
			fileExists(filepath.Join(dir, "result.json")) {
			bundles = append(bundles, entry.Name())
		}
	}
	sort.Strings(bundles)
	return bundles
}

func fileExists(path string) bool {
	_, err := os.Stat(path)
	return err == nil
}

func assertNoRemainingCloneDirs(t *testing.T, execRoot string) {
	t.Helper()

	entries, err := os.ReadDir(execRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return
		}
		t.Fatalf("read execution temp root %s: %v", execRoot, err)
	}
	var leftovers []string
	for _, entry := range entries {
		if entry.IsDir() && strings.HasPrefix(entry.Name(), ExecuteBeadClonePrefix) {
			leftovers = append(leftovers, entry.Name())
		}
	}
	if len(leftovers) > 0 {
		t.Fatalf("expected no lingering local-clone attempt directories under %s, found %s", execRoot, strings.Join(leftovers, ", "))
	}
}

func waitForSecondBoundary() {
	for {
		if time.Now().UTC().Nanosecond() < 150*time.Millisecond {
			return
		}
		time.Sleep(10 * time.Millisecond)
	}
}

func extractValue(output, prefix string) string {
	for _, line := range strings.Split(output, "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, prefix) {
			return strings.TrimSpace(strings.TrimPrefix(line, prefix))
		}
	}
	return ""
}

func attemptIDFromPreserveRef(ref string) string {
	leaf := strings.TrimSpace(ref)
	if idx := strings.LastIndex(leaf, "/"); idx >= 0 {
		leaf = leaf[idx+1:]
	}
	idx := strings.LastIndex(leaf, "-")
	if idx < 0 {
		return ""
	}
	return leaf[:idx]
}

func attemptTimestampPrefix(attemptID string) string {
	if attemptID == "" {
		return ""
	}
	parts := strings.SplitN(attemptID, "-", 2)
	return parts[0]
}

func uniqueStrings(values []string) []string {
	seen := make(map[string]struct{}, len(values))
	uniq := make([]string, 0, len(values))
	for _, value := range values {
		if _, ok := seen[value]; ok {
			continue
		}
		seen[value] = struct{}{}
		uniq = append(uniq, value)
	}
	sort.Strings(uniq)
	return uniq
}

