func acquireExclusiveLock(lockFile *os.File) error {
	if lockFile == nil {
		return fmt.Errorf("lock file is nil")
	}
	return inTreeLockAcquire(lockFile)
}

func releaseExclusiveLock(lockFile *os.File) error {
	if lockFile == nil {
		return nil
	}
	return inTreeLockRelease(lockFile)
}

