	if result.ExitCode != 0 {
		t.Fatalf("expected exit 0, got %d", result.ExitCode)
	}
	content, ferr := os.ReadFile(filepath.Join(repo, "out.txt"))
	if ferr != nil {
		t.Fatalf("out.txt not found: %v", ferr)
