	if strings.TrimSpace(string(content)) != "hello" {
		t.Fatalf("expected 'hello' in x.txt, got %q", string(content))
	}
	if gitLogCount(t, repo) != 2 {
		t.Fatalf("expected 2 commits, got %d", gitLogCount(t, repo))
	}
}

