func writeTryDirective(t *testing.T, mode string) string {
	t.Helper()

	directivePath := filepath.Join(t.TempDir(), "directive.txt")
	var shell string
	switch mode {
	case "slow-success":
		shell = `case "$PWD" in *"/.execute-bead-clone-"*) sleep 1; printf '%s\n' "try-output for ${DDX_BEAD_ID}" > "try-${DDX_BEAD_ID}.txt"; git add "try-${DDX_BEAD_ID}.txt"; git -c commit.gpgsign=false commit -q -m "feat: ${DDX_BEAD_ID} try";; *) :;; esac`
	default:
		shell = `case "$PWD" in *"/.execute-bead-clone-"*) printf '%s\n' "try-output for ${DDX_BEAD_ID}" > "try-${DDX_BEAD_ID}.txt"; git add "try-${DDX_BEAD_ID}.txt"; git -c commit.gpgsign=false commit -q -m "feat: ${DDX_BEAD_ID} try";; *) :;; esac`
	}

	require.NoError(t, os.WriteFile(directivePath, []byte("run "+shell+"\n"), 0o644))
	return directivePath
}

func runConcurrentTrySubprocesses(t *testing.T, bin, projectRoot string, env []string, beadIDs []string, directivePath string, noMerge bool) []trySubprocessResult {
	t.Helper()

	results := make([]trySubprocessResult, len(beadIDs))
	var wg sync.WaitGroup
	start := make(chan struct{})
	for i, beadID := range beadIDs {
		i, beadID := i, beadID
		wg.Add(1)
		go func() {
			defer wg.Done()
			<-start
			results[i] = runTrySubprocess(t, bin, projectRoot, env, beadID, directivePath, noMerge)
		}()
	}
	close(start)
	wg.Wait()
	return results
}

func runTrySubprocess(t *testing.T, bin, projectRoot string, env []string, beadID, directivePath string, noMerge bool) trySubprocessResult {
	t.Helper()

	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
	defer cancel()

	args := []string{
		"try", beadID,
		"--project", projectRoot,
		"--harness", "script",
		"--model", directivePath,
		"--attempt-backend", "local-clone",
		"--no-review", "--no-review-i-know-what-im-doing",
	}
	if noMerge {
		args = append(args, "--no-merge")
	}

	cmd := exec.CommandContext(ctx, bin, args...)
	cmd.Dir = projectRoot
	cmd.Env = env
	out, err := cmd.CombinedOutput()
	return trySubprocessResult{
		beadID:   beadID,
		output:   string(out),
		err:      err,
		exitCode: exitCodeOf(err),
	}
}

func exitCodeOf(err error) int {
	if err == nil {
		return 0
	}
	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) {
		return exitErr.ExitCode()
	}
	return -1
}

func assertAllTrySubprocessesFinished(t *testing.T, results []trySubprocessResult, wantExitCode int) {
	t.Helper()

	for i, res := range results {
		require.NoErrorf(t, res.err, "subprocess %d (%s) failed unexpectedly: %s", i, res.beadID, res.output)
		assert.Equalf(t, wantExitCode, res.exitCode, "subprocess %d (%s) exit code mismatch: %s", i, res.beadID, res.output)
		assert.Containsf(t, res.output, "status: success", "subprocess %d (%s) must report a success status", i, res.beadID)
		assert.Containsf(t, res.output, "result_rev:", "subprocess %d (%s) must report a result revision", i, res.beadID)
	}
}

