func completeExecutionBundles(t *testing.T, projectRoot string) []string {
	t.Helper()

	execDir := ddxroot.JoinProject(projectRoot, "executions")
	entries, err := os.ReadDir(execDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		t.Fatalf("read execution dir %s: %v", execDir, err)
	}
	var bundles []string
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dir := filepath.Join(execDir, entry.Name())
		if fileExists(filepath.Join(dir, "manifest.json")) &&
			fileExists(filepath.Join(dir, "prompt.md")) &&
			fileExists(filepath.Join(dir, "result.json")) {
			bundles = append(bundles, entry.Name())
		}
	}
	sort.Strings(bundles)
	return bundles
}

func fileExists(path string) bool {
	_, err := os.Stat(path)
	return err == nil
}

func assertNoRemainingCloneDirs(t *testing.T, execRoot string) {
	t.Helper()

	entries, err := os.ReadDir(execRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return
		}
		t.Fatalf("read execution temp root %s: %v", execRoot, err)
	}
	var leftovers []string
	for _, entry := range entries {
		if entry.IsDir() && strings.HasPrefix(entry.Name(), localCloneAttemptPrefix) {
			leftovers = append(leftovers, entry.Name())
		}
	}
	if len(leftovers) > 0 {
		t.Fatalf("expected no lingering local-clone attempt directories under %s, found %s", execRoot, strings.Join(leftovers, ", "))
	}
}

func waitForSecondBoundary() {
	for {
		if time.Now().UTC().Nanosecond() < int(150*time.Millisecond) {
			return
		}
		time.Sleep(10 * time.Millisecond)
	}
}

func extractValue(output, prefix string) string {
	for _, line := range strings.Split(output, "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, prefix) {
			return strings.TrimSpace(strings.TrimPrefix(line, prefix))
		}
	}
	return ""
}

func attemptIDFromPreserveRef(ref string) string {
	leaf := strings.TrimSpace(ref)
	if idx := strings.LastIndex(leaf, "/"); idx >= 0 {
		leaf = leaf[idx+1:]
	}
	idx := strings.LastIndex(leaf, "-")
	if idx < 0 {
		return ""
	}
	return leaf[:idx]
}

func attemptTimestampPrefix(attemptID string) string {
	if attemptID == "" {
		return ""
	}
	parts := strings.SplitN(attemptID, "-", 2)
	return parts[0]
}

func uniqueStrings(values []string) []string {
	seen := make(map[string]struct{}, len(values))
	uniq := make([]string, 0, len(values))
	for _, value := range values {
		if _, ok := seen[value]; ok {
			continue
		}
		seen[value] = struct{}{}
		uniq = append(uniq, value)
	}
	sort.Strings(uniq)
	return uniq
}

func runGitIntegLocal(t *testing.T, dir string, args ...string) string {
	t.Helper()

	cmd := exec.Command("git", args...)
	cmd.Dir = dir
	cmd.Env = scrubbedGitEnvLocal()
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("git %v in %s: %v\n%s", args, dir, err, out)
	}
	return strings.TrimSpace(string(out))
}

func scrubbedGitEnvLocal() []string {
	parent := os.Environ()
	env := make([]string, 0, len(parent))
	for _, kv := range parent {
		if strings.HasPrefix(kv, "GIT_") {
			continue
		}
		env = append(env, kv)
	}
	return env
}

