			outputLines = append(outputLines, fmt.Sprintf("commit %q", msg))

		default:
			execErr = fmt.Errorf("script harness: unknown directive %q at index %d", verb, i)
			goto done
		}
	}

done:
	elapsed := time.Since(start)
	sessionID := fmt.Sprintf("script-%d", start.UnixNano())

	result := &Result{
		Harness:        "script",
		Provider:       "script",
		RouteReason:    "direct-override",
		Model:          directivePath,
		Output:         strings.Join(outputLines, "\n"),
		ExitCode:       exitCode,
		DurationMS:     int(elapsed.Milliseconds()),
		AgentSessionID: sessionID,
	}
	if execErr != nil {
		result.Error = execErr.Error()

func projectBoundPath(projectRoot, path string) (string, error) {
	if strings.TrimSpace(path) == "" {
		return "", fmt.Errorf("path is empty")
	}
	if !filepath.IsAbs(path) {
		path = filepath.Join(projectRoot, filepath.FromSlash(path))
	}
	cleanRoot := filepath.Clean(projectRoot)
	cleanPath := filepath.Clean(path)
	rel, err := filepath.Rel(cleanRoot, cleanPath)
	if err != nil {
		return "", err
	}
	if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return "", fmt.Errorf("path escapes project root: %s", path)
	}
	return cleanPath, nil
}

